// src/scripts/daf/AudioGraph.ts
// Owns: AudioContext + node creation, wiring, and live parameter updates.
// Knows nothing about UI, timers, or device enumeration.
// webkitAudioContext is declared in src/globals.d.ts and available project-wide.

import {
  loadPitchShifterWorklet,
  semitonesToRatio,
  getFAFLatencyMs,
  getOLALatencyMs,
  DEFAULT_FAF_MODE,
  DEFAULT_VOICE_PROFILE,
  VOICE_PROFILES,
  type FAFMode,
} from './PitchShifterWorklet';
import { runBenchmark, type BenchmarkResult } from './BenchmarkManager';

interface AudioGraphConfig {
  delayTime: number;
  gain: number;
  pitchShift: number;          // semitones; 0 = single FAF off
  multiFAFSemitones?: number[]; // non-empty = multi-FAF mode (overrides pitchShift)
}

interface AudioNodes {
  source: MediaStreamAudioSourceNode | null;
  gainNode: GainNode | null;
  delayNode: DelayNode | null;
}

export class AudioGraph {
  private _ctx: AudioContext | null = null;
  private _nodes: AudioNodes = { source: null, gainNode: null, delayNode: null };

  // ── FAF state ────────────────────────────────────────────────────────────────
  // _fafNodes: one entry per active pitch-shifted signal (1 = single FAF, N = multi)
  // _fafSumNode: normalising GainNode that mixes all FAF signals before delayNode
  //              gain = 1/N so perceived loudness stays constant regardless of count
  private _fafNodes: AudioWorkletNode[] = [];
  private _fafSumNode: GainNode | null = null;
  private _fafActive = false;    // true when any FAF nodes are wired in
  private _workletReady = false; // true once addModule() has resolved
  private _pitchFloor: number = VOICE_PROFILES[DEFAULT_VOICE_PROFILE].pitchFloor;
  private _fafMode: FAFMode = DEFAULT_FAF_MODE;

  /** Measured input + output round-trip floor in ms (populated after context starts). */
  measuredFloorMs: number | null = null;

  constructor(deviceSampleRate?: number | null) {
    this._init(deviceSampleRate);
  }

  // ── public getters ──────────────────────────────────────────────────────────

  get context(): AudioContext | null { return this._ctx; }
  get state(): string { return this._ctx?.state ?? 'closed'; }
  get gainValue(): number { return this._nodes.gainNode?.gain.value ?? 1; }

  /**
   * Algorithmic latency added by the active FAF processor when active.
   * OLA:   OLA_LOOKBACK / sampleRate ≈ 8.9 ms at 48 kHz.
   * PSOLA: 2 × T_MAX / sampleRate — depends on pitchFloor.
   * Returns 0 when FAF is bypassed.
   */
  get fafLatencyMs(): number {
    if (!this._fafActive || !this._ctx) return 0;
    return this._fafMode === 'ola'
      ? getOLALatencyMs(this._ctx.sampleRate)
      : getFAFLatencyMs(this._pitchFloor, this._ctx.sampleRate);
  }

  set pitchFloor(hz: number) { this._pitchFloor = hz; }
  set fafMode(mode: FAFMode) { this._fafMode = mode; }

  // ── lifecycle ───────────────────────────────────────────────────────────────

  connect(stream: MediaStream, config: AudioGraphConfig): void {
    const ctx = this._ctx!;
    const nodes = this._nodes;

    nodes.source = ctx.createMediaStreamSource(stream);
    nodes.gainNode = ctx.createGain();
    nodes.delayNode = ctx.createDelay(0.5);

    const minDelay = 0.000001;
    nodes.delayNode.delayTime.value = Math.max(minDelay, config.delayTime / 1000);
    nodes.gainNode.gain.value = config.gain;

    // Base wiring: source → delay → gain → destination
    // FAF nodes splice themselves in after the worklet loads
    nodes.source.connect(nodes.delayNode);
    nodes.delayNode.connect(nodes.gainNode);
    nodes.gainNode.connect(ctx.destination);

    // Multi-FAF takes priority over single-FAF
    const fafSemitones = config.multiFAFSemitones?.length
      ? config.multiFAFSemitones
      : config.pitchShift !== 0 ? [config.pitchShift] : [];

    if (fafSemitones.length > 0) {
      this.setFAFNodes(fafSemitones).catch(e => console.warn('FAF init failed:', e));
    }
  }

  disconnect(): void {
    this._teardownFAF();
    const { source, gainNode, delayNode } = this._nodes;
    [source, gainNode, delayNode].forEach(node => {
      try { node?.disconnect(); } catch { /* ignore */ }
    });
    this._nodes = { source: null, gainNode: null, delayNode: null };
  }

  async close(): Promise<void> {
    this.disconnect();
    if (this._ctx && this._ctx.state !== 'closed') {
      try { await this._ctx.close(); } catch (e) {
        console.error('Error closing AudioContext:', e);
      }
    }
    this._ctx = null;
    this.measuredFloorMs = null;
    this._workletReady = false;
  }

  async resume(): Promise<void> {
    if (this._ctx?.state === 'suspended') await this._ctx.resume();
  }

  // ── parameter updates ───────────────────────────────────────────────────────

  setDelayTime(ms: number): void {
    if (!this._ctx || !this._nodes.delayNode) return;
    const minDelay = 0.000001;
    const actualSecs = ms <= 0 ? minDelay : ms / 1000;
    this._nodes.delayNode.delayTime.setValueAtTime(actualSecs, this._ctx.currentTime);
  }

  setGain(value: number): void {
    if (!this._ctx || !this._nodes.gainNode) return;
    this._nodes.gainNode.gain.setValueAtTime(value, this._ctx.currentTime);
  }

  /**
   * Single-FAF convenience wrapper.
   * semitones = 0 → bypass; semitones ≠ 0 → single node.
   */
  async setFAFSemitones(semitones: number): Promise<void> {
    return this.setFAFNodes(semitones === 0 ? [] : [semitones]);
  }

  /**
   * Canonical FAF method — handles single and multi-FAF uniformly.
   *
   * semitones = []       → bypass (zero worklet overhead)
   * semitones = [n]      → single FAF at n semitones
   * semitones = [a,b,…]  → multi-FAF; signals mix through a normalising gain
   *                         (amplitude × 1/N) before the delay node.
   *
   * Same count, already active → only pitchRatio params updated (no graph surgery).
   * Count changed / first enable → full teardown + rebuild.
   *
   * Topology (active):
   *   source ──→ fafNode[0] ──→ sumGain(1/N) ──→ delayNode → gainNode → out
   *          ├──→ fafNode[1] ──↗
   *          └──→ fafNode[…] ──↗
   *
   * Topology (bypass):
   *   source → delayNode → gainNode → out
   */
  async setFAFNodes(semitones: number[]): Promise<void> {
    if (!this._ctx || !this._nodes.source || !this._nodes.delayNode) return;

    const { source, delayNode } = this._nodes;

    // ── Bypass ────────────────────────────────────────────────────────────────
    if (semitones.length === 0) {
      if (!this._fafActive) return;
      this._teardownFAF();
      try { source.connect(delayNode); } catch { /* ignore */ }
      console.log('FAF bypassed');
      return;
    }

    // ── Load worklet on first use ─────────────────────────────────────────────
    if (!this._workletReady) {
      try {
        await loadPitchShifterWorklet(this._ctx);
        this._workletReady = true;
      } catch (e) {
        console.error('PitchShifterWorklet failed to load:', e);
        throw e;
      }
    }

    // Re-check after await — user may have stopped DAF mid-load
    if (!this._ctx || !this._nodes.source || !this._nodes.delayNode) return;

    // ── Same count and already active → update ratios only ────────────────────
    if (semitones.length === this._fafNodes.length && this._fafActive) {
      for (let i = 0; i < semitones.length; i++) {
        const param = this._fafNodes[i]!.parameters.get('pitchRatio');
        if (param) param.value = semitonesToRatio(semitones[i]!);
      }
      const fmt = semitones.map(s => `${s > 0 ? '+' : ''}${s}`).join(', ');
      console.log(`FAF ratios updated: [${fmt}] st`);
      return;
    }

    // ── Rebuild graph ─────────────────────────────────────────────────────────
    this._teardownFAF(); // clears _fafNodes, _fafSumNode, _fafActive

    // Remove direct source→delay path
    try { this._nodes.source.disconnect(this._nodes.delayNode); } catch { /* ignore */ }

    const n = semitones.length;

    // Normalising sum node: keeps perceived loudness constant regardless of N
    this._fafSumNode = this._ctx.createGain();
    this._fafSumNode.gain.value = 1 / n;

    for (const st of semitones) {
      const processorName = this._fafMode === 'ola' ? 'pitch-shifter-ola' : 'pitch-shifter-psola';
      const node = new AudioWorkletNode(this._ctx, processorName, {
        numberOfInputs: 1,
        numberOfOutputs: 1,
        outputChannelCount: [1],
        processorOptions: this._fafMode === 'psola'
          ? { pitchFloor: this._pitchFloor }
          : {},
      });
      const param = node.parameters.get('pitchRatio');
      if (param) param.value = semitonesToRatio(st);
      this._nodes.source.connect(node);
      node.connect(this._fafSumNode);
      this._fafNodes.push(node);
    }

    this._fafSumNode.connect(this._nodes.delayNode);
    this._fafActive = true;

    const fmt = semitones.map(s => `${s > 0 ? '+' : ''}${s}`).join(', ');
    console.log(`FAF enabled [${n} signal${n > 1 ? 's' : ''}]: [${fmt}] st`);
  }

  // ── event hook ──────────────────────────────────────────────────────────────

  onStateChange(cb: (state: string) => void): void {
    this._ctx?.addEventListener('statechange', (e) => {
      // Read state from the event target directly — this._ctx may already be
      // null by the time the final 'closed' statechange fires after close().
      const state = (e.target as AudioContext).state;
      cb(state);
    });
  }

  // ── latency measurement ─────────────────────────────────────────────────────

  measureLatencyFloor(stream: MediaStream | null): void {
    if (!this._ctx) return;
    try {
      const outputMs =
        ((this._ctx.baseLatency ?? 0) + (this._ctx.outputLatency ?? 0)) * 1000;
      let inputMs = 0;
      try {
        const settings = stream?.getAudioTracks?.()?.[0]?.getSettings?.();
        if (settings?.latency) inputMs = settings.latency * 1000;
      } catch { /* browser differences */ }

      const totalMs = inputMs + outputMs;
      this.measuredFloorMs = totalMs;

      console.log(
        `Latency floor: ${outputMs.toFixed(1)}ms (output)` +
        (inputMs
          ? ` + ${inputMs.toFixed(1)}ms (input)`
          : ' + 0 (input unknown)') +
        ` = ${totalMs.toFixed(1)}ms total`,
      );
      if (totalMs > 25) {
        console.warn(
          `Round-trip floor ${totalMs.toFixed(1)}ms > 25ms — slap-back likely at low delay settings`,
        );
      }
    } catch { /* ignore */ }
  }

  // ── benchmark ───────────────────────────────────────────────────────────────

  /**
   * Run a full latency + jitter benchmark on the live AudioContext.
   * The context must be running. Takes ~600 ms.
   */
  async benchmark(stream: MediaStream | null): Promise<BenchmarkResult> {
    if (!this._ctx) throw new Error('AudioContext not initialised');
    return runBenchmark(this._ctx, stream, this.fafLatencyMs);
  }

  // ── private ─────────────────────────────────────────────────────────────────

  /**
   * Disconnect and discard all FAF nodes without touching source/delay/gain.
   * Safe to call when already bypassed.
   */
  private _teardownFAF(): void {
    const source = this._nodes.source;
    for (const node of this._fafNodes) {
      if (source) { try { source.disconnect(node); } catch { /* ignore */ } }
      try { node.disconnect(); } catch { /* ignore */ }
    }
    this._fafNodes = [];
    if (this._fafSumNode) {
      try { this._fafSumNode.disconnect(); } catch { /* ignore */ }
      this._fafSumNode = null;
    }
    this._fafActive = false;
  }

  private _init(deviceSampleRate?: number | null): void {
    const opts: AudioContextOptions = { latencyHint: 0 };
    if (deviceSampleRate && Number.isFinite(deviceSampleRate)) {
      opts.sampleRate = deviceSampleRate;
    }
    const Ctx = window.AudioContext ?? window.webkitAudioContext!;
    this._ctx = new Ctx(opts);
  }
}
