// src/scripts/daf/ErrorReporter.ts
// Single place for all Sentry instrumentation.
// Every method null-checks window.Sentry and swallows errors so a
// missing / blocked Sentry script never crashes the app.

export interface MicErrorClassification {
  message: string;
  tag: string;
}

export class ErrorReporter {

  // ── error classification ────────────────────────────────────────────────────

  classifyMicError(error: unknown): MicErrorClassification {
    const err = error as { name?: string; message?: string } | null;
    const name = err?.name ?? '';
    const message = (err?.message ?? '').toLowerCase();

    if (name === 'NotAllowedError' && message.includes('system')) {
      return {
        tag: 'permission_denied_system',
        message:
          'Your operating system is blocking microphone access. ' +
          'Please check your system privacy settings ' +
          '(macOS: System Settings → Privacy & Security → Microphone; ' +
          'Windows: Settings → Privacy → Microphone) and allow access, then try again.',
      };
    }
    if (name === 'NotAllowedError' && message.includes('avaudiosession')) {
      return {
        tag: 'permission_denied_ios_no_device',
        message:
          'No microphone was found on your device. ' +
          'Please plug in a headset or enable microphone access in ' +
          'Settings → Safari → Microphone, then try again.',
      };
    }
    if (name === 'NotAllowedError' && message.includes('dismiss')) {
      return {
        tag: 'permission_dismissed',
        message:
          'Microphone access was dismissed. ' +
          'Please tap "Start DAF" again and click "Allow" when prompted.',
      };
    }
    if (
      name === 'NotAllowedError' ||
      name === 'PermissionDeniedError' ||
      message.includes('not allowed') ||
      message.includes('denied')
    ) {
      return {
        tag: 'permission_denied_user',
        message:
          "Microphone access was denied. " +
          "Please click the 🔒 / 🎙️ icon in your browser's address bar, " +
          'set Microphone to "Allow", refresh the page, and try again.',
      };
    }
    if (
      name === 'NotFoundError' ||
      message.includes('not found') ||
      message.includes('device')
    ) {
      return {
        tag: 'device_not_found',
        message:
          'The selected microphone could not be found. ' +
          'It may have been unplugged. Please check your microphone ' +
          'connection and try again.',
      };
    }
    return {
      tag: 'unknown',
      message:
        'Could not access your microphone. ' +
        'Please make sure a microphone is connected and this page has ' +
        'permission to use it, then try again.',
    };
  }

  // ── audio initialisation ────────────────────────────────────────────────────

  audioInitFailed(
    err: unknown,
    {
      deviceId = null as string | null,
      micErrorTag = 'unknown',
      audioContextState = 'not_initialized',
      availableDeviceCount = 0,
      hasUserMedia = !!(navigator.mediaDevices?.getUserMedia),
      secureContext = window.isSecureContext,
      preAcquired = false,
    } = {},
  ): void {
    this._capture(sentry =>
      sentry.captureException(err, {
        tags: { mechanism: 'audio_init', mic_error_type: micErrorTag, secure_context: secureContext },
        extra: { requestedDeviceId: deviceId, audioContextState, availableDeviceCount, hasUserMedia, preAcquired },
      }),
    );
  }

  // ── audio resume ────────────────────────────────────────────────────────────

  audioResumedAfterRetries(attempts: number): void {
    if (attempts <= 1) return;
    this._capture(sentry =>
      sentry.captureMessage('Audio resumed after multiple attempts', {
        level: 'warning',
        extra: { attempts },
      }),
    );
  }

  // ── microphone acquisition ──────────────────────────────────────────────────

  micAcquired(settings: MediaTrackSettings, label: string): void {
    const ctx = {
      autoGainControl: settings.autoGainControl,
      echoCancellation: settings.echoCancellation,
      noiseSuppression: settings.noiseSuppression,
      sampleRate: settings.sampleRate,
      label: label || 'Unknown',
    };
    this._capture(sentry => {
      if (typeof sentry.setContext === 'function') {
        sentry.setContext('mic_settings', ctx);
      } else if (typeof sentry.configureScope === 'function') {
        sentry.configureScope(scope => scope.setContext('mic_settings', ctx));
      }
    });
  }

  // ── page lifecycle breadcrumbs ──────────────────────────────────────────────

  visibilityChanged(state: string): void {
    this._capture(sentry =>
      sentry.addBreadcrumb({
        category: 'ui.lifecycle',
        message: `Visibility changed to ${state}`,
        level: 'info',
      }),
    );
  }

  // ── private ─────────────────────────────────────────────────────────────────

  private _capture(fn: (sentry: NonNullable<Window['Sentry']>) => void): void {
    if (!window.Sentry) return;
    try { fn(window.Sentry); } catch (e) {
      console.warn('ErrorReporter: Sentry call failed', e);
    }
  }
}
