// src/scripts/daf/PitchShifterWorklet.ts
// Two FAF pitch-shifting implementations for the Web Audio API.
// Both are registered in a single Blob URL so addModule() is called once.
//
// ── Processor names ──────────────────────────────────────────────────────────
//   'pitch-shifter-ola'   → Fixed-Anchor Grain Resampling  (Low Latency Mode)
//   'pitch-shifter-psola' → TD-PSOLA with YIN detector     (High-Fidelity Mode)
//
// ── Pitch ratio range ────────────────────────────────────────────────────────
//   Clinical slider: ±8 semitones  →  ratio ∈ [2^(-8/12), 2^(8/12)] ≈ [0.630, 1.587]
//   Cents equivalent: ±800 cents   →  same range.
//
//   Both processors clamp pitchRatio to [R_MIN, R_MAX = 2.0].
//
//   NOTE on R_MIN: The old value was 0.5 (one full octave down = 12 semitones).
//   Since the UI slider is hard-limited to ±8 semitones, the system never reaches
//   a pitch ratio of 0.5 in practice. The minimum reachable ratio is 2^(-8/12) ≈ 0.630.
//   Using R_MIN = 0.6 (≈ 9 semitones down) is therefore safe — it gives 1 semitone
//   of headroom beyond the slider limit — and reduces OLA LOOKBACK from 512 → 427
//   samples (10.7 ms → 8.9 ms at 48 kHz).
//   PSOLA is unaffected by R_MIN in terms of latency (its latency derives from T_MAX,
//   not R_MIN), but we harmonise the clamp at 0.6 for both processors.

// ── Exported types ────────────────────────────────────────────────────────────

export type FAFMode = 'psola' | 'ola';

/** Display label for each FAF mode. */
export const FAF_MODE_LABELS: Record<FAFMode, string> = {
  psola: 'High-Fidelity',
  ola:   'Low Latency',
};

export const DEFAULT_FAF_MODE: FAFMode = 'psola';

// ── OLA constants ─────────────────────────────────────────────────────────────

/** Minimum pitch ratio for OLA. 0.6 ≈ 9 st down — safe for ±8 st slider. */
export const OLA_R_MIN = 0.6;

/** OLA grain size in samples. */
export const OLA_GRAIN = 256;

/**
 * OLA lookback depth = ceil(GRAIN / R_MIN) + 1.
 * The +1 guards the linear interpolation from reading inBuf[inW] (unwritten).
 * At r = R_MIN, srcPos_max = anchor + GRAIN/R_MIN = inW - LOOKBACK + GRAIN/R_MIN.
 * With LOOKBACK = ceil(GRAIN/R_MIN) + 1 this evaluates to inW - 1 + fraction < inW. ✓
 */
export const OLA_LOOKBACK = Math.ceil(OLA_GRAIN / OLA_R_MIN) + 1; // 428

/** Compute OLA algorithmic latency in ms for a given sample rate. */
export function getOLALatencyMs(sampleRate: number): number {
  return (OLA_LOOKBACK / sampleRate) * 1000;
}

// ── PSOLA / voice profile constants ──────────────────────────────────────────

export const VOICE_PROFILES = {
  deep:   { pitchFloor: 80,  label: 'Deep',        latencyMs: 25.0 },
  normal: { pitchFloor: 120, label: 'Normal',       latencyMs: 16.6 },
  high:   { pitchFloor: 150, label: 'High-pitched', latencyMs: 13.3 },
} as const;

export type VoiceProfileKey = keyof typeof VOICE_PROFILES;
export const DEFAULT_VOICE_PROFILE: VoiceProfileKey = 'normal';

/** Compute PSOLA algorithmic latency in ms: 2×T_MAX/sampleRate×1000. */
export function getFAFLatencyMs(pitchFloor: number, sampleRate: number): number {
  return (2 * Math.floor(sampleRate / pitchFloor) / sampleRate) * 1000;
}

// Kept for backward compat; equals VOICE_PROFILES.normal at 48kHz ≈ 16.6ms.
export const FAF_LATENCY_MS = VOICE_PROFILES.normal.latencyMs;

export const FAF_R_MIN = OLA_R_MIN;  // harmonised: both clamped at 0.6
export const FAF_R_MAX = 2.0;

/** Convert semitones to a linear pitch ratio. */
export function semitonesToRatio(semitones: number): number {
  return Math.pow(2, semitones / 12);
}

// ── Internal constants (embedded in worklet string via template literals) ─────

const _R_MIN    = OLA_R_MIN;    // 0.6
const _R_MAX    = FAF_R_MAX;    // 2.0
const _OLA_G    = OLA_GRAIN;    // 256
const _OLA_H    = 128;          // hop = 50% of grain
const _OLA_LB   = OLA_LOOKBACK; // 428
const _OLA_IN   = 8192;
const _OLA_OUT  = 2048;
const _PSOLA_IN   = 8192;
const _PSOLA_OUT  = 4096;
const _HTAB       = 1024;
const _YIN_W      = 256;
const _YIN_INT    = 4;
const _YIN_THR    = 0.15;

// ── Combined worklet source ───────────────────────────────────────────────────

const COMBINED_WORKLET_CODE = /* js */`
(function () {
  'use strict';

  // ── Shared constants ────────────────────────────────────────────────────────
  const R_MIN = ${_R_MIN};
  const R_MAX = ${_R_MAX};

  // Pre-computed Hann table shared by both processors.
  const HTAB   = ${_HTAB};
  const HTABM1 = HTAB - 1;
  const HANN   = new Float32Array(HTAB);
  for (let i = 0; i < HTAB; i++) {
    HANN[i] = 0.5 - 0.5 * Math.cos(2 * Math.PI * i / (HTAB - 1));
  }

  // ── Fixed-Anchor Grain Resampling (OLA) ────────────────────────────────────
  //
  // Pitch shift WITHOUT timing/delay change.
  // Anchor is fixed at inW - LOOKBACK every hop.
  // Pitch is changed by resampling readSpan = G/r input samples into G output.
  // r > 1: readSpan < G → higher frequency; r < 1: readSpan > G → lower.
  // Latency: LOOKBACK/sampleRate ≈ 8.9 ms at 48 kHz.
  //
  // R_MIN = ${_R_MIN} (safe for ±8 st slider; min reachable ratio ≈ 0.630).
  // See top-of-file NOTE for R_MIN rationale.

  const OLA_G    = ${_OLA_G};
  const OLA_H    = ${_OLA_H};
  const OLA_LB   = ${_OLA_LB};
  const OLA_INSZ = ${_OLA_IN};
  const OLA_OUTS = ${_OLA_OUT};
  const OLA_INM  = OLA_INSZ - 1;
  const OLA_OUTM = OLA_OUTS - 1;

  class OLAPitchShifter extends AudioWorkletProcessor {
    static get parameterDescriptors() {
      return [{ name: 'pitchRatio', defaultValue: 1.0,
                minValue: R_MIN, maxValue: R_MAX, automationRate: 'k-rate' }];
    }
    constructor() {
      super();
      this._inBuf  = new Float32Array(OLA_INSZ);
      this._outBuf = new Float32Array(OLA_OUTS);
      this._inW  = 0;
      this._outW = 0;
      this._outR = 0;
    }
    process(inputs, outputs, parameters) {
      const inp = inputs[0]?.[0];
      const out = outputs[0]?.[0];
      if (!inp || !out) return true;
      const N = inp.length;
      const r = Math.max(R_MIN, Math.min(R_MAX, parameters.pitchRatio[0]));
      for (let i = 0; i < N; i++) {
        this._inBuf[this._inW++ & OLA_INM] = inp[i];
      }
      if (this._inW < OLA_LB + OLA_G) { out.fill(0); return true; }
      const anchor   = this._inW - OLA_LB;
      const readSpan = OLA_G / r;
      // Amplitude normalisation: COLA sum ≈ r with hop=H and grain=G.
      // Scale by 1/r to maintain unity gain across all pitch ratios.
      const gain = 1 / r;
      for (let i = 0; i < OLA_G; i++) {
        const srcPos = anchor + (i / (OLA_G - 1)) * readSpan;
        const ip = srcPos | 0;
        const fr = srcPos - ip;
        const s  = this._inBuf[ip & OLA_INM] * (1.0 - fr)
                 + this._inBuf[(ip + 1) & OLA_INM] * fr;
        this._outBuf[(this._outW + i) & OLA_OUTM] += s * HANN[Math.round(i / (OLA_G - 1) * HTABM1)] * gain;
      }
      this._outW += OLA_H;
      if (this._outW - this._outR >= N) {
        for (let i = 0; i < N; i++) {
          const idx = this._outR++ & OLA_OUTM;
          out[i] = this._outBuf[idx];
          this._outBuf[idx] = 0.0;
        }
      } else {
        out.fill(0);
      }
      return true;
    }
  }

  // ── PSOLA (Pitch Synchronous Overlap-Add) ───────────────────────────────────
  //
  // YIN pitch detector → pitch-synchronous grains → coherent overlap-add.
  // Latency: 2 × T_MAX = 2 × floor(sampleRate / pitchFloor).
  // pitchFloor passed via processorOptions at AudioWorkletNode creation.
  // Voice type buttons (Deep/Normal/High-pitched) control pitchFloor.

  const PSO_INSZ = ${_PSOLA_IN};
  const PSO_OUTS = ${_PSOLA_OUT};
  const PSO_INM  = PSO_INSZ - 1;
  const PSO_OUTM = PSO_OUTS - 1;
  const YIN_W    = ${_YIN_W};
  const YIN_INT  = ${_YIN_INT};
  const YIN_THR  = ${_YIN_THR};

  class PSOLAPitchShifter extends AudioWorkletProcessor {
    static get parameterDescriptors() {
      return [{ name: 'pitchRatio', defaultValue: 1.0,
                minValue: R_MIN, maxValue: R_MAX, automationRate: 'k-rate' }];
    }
    constructor(options) {
      super();
      const pitchFloor  = options?.processorOptions?.pitchFloor ?? 120;
      this._tMin    = Math.ceil(sampleRate / 500);
      this._tMax    = Math.floor(sampleRate / pitchFloor);
      this._latency = 2 * this._tMax;
      this._inBuf  = new Float32Array(PSO_INSZ);
      this._outBuf = new Float32Array(PSO_OUTS);
      this._inW  = 0;
      this._outW = 0;
      this._outR = 0;
      this._synthRemain = 0;
      this._lastT0  = Math.round((this._tMin + this._tMax) / 2);
      this._voiced  = false;
      this._yinCount = 0;
    }
    process(inputs, outputs, parameters) {
      const inp = inputs[0]?.[0];
      const out = outputs[0]?.[0];
      if (!inp || !out) return true;
      const N = inp.length;
      const r = Math.max(R_MIN, Math.min(R_MAX, parameters.pitchRatio[0]));
      for (let i = 0; i < N; i++) {
        this._inBuf[this._inW++ & PSO_INM] = inp[i];
      }
      if (this._inW < this._latency + this._tMax + YIN_W) { out.fill(0); return true; }
      this._synthRemain -= N;
      while (this._synthRemain <= 0) this._generateGrain(r);
      if (this._outW - this._outR >= N) {
        for (let i = 0; i < N; i++) {
          const idx = this._outR++ & PSO_OUTM;
          out[i] = this._outBuf[idx];
          this._outBuf[idx] = 0.0;
        }
      } else {
        out.fill(0);
      }
      return true;
    }
    _generateGrain(r) {
      if (--this._yinCount <= 0) { this._runYIN(); this._yinCount = YIN_INT; }
      const anchor = this._inW - this._latency;
      let grainStart, grainSize, synthHop, grainGain;
      if (this._voiced) {
        const T0   = this._lastT0;
        const mark = this._findPitchMark(anchor, T0);
        grainStart = mark - T0;
        grainSize  = 2 * T0;
        synthHop   = Math.max(1, Math.round(T0 / r));
        grainGain  = 1 / r;
      } else {
        grainSize  = 128;
        grainStart = anchor - 64;
        synthHop   = 64;
        grainGain  = 1.0;
      }
      this._overlapAdd(grainStart, grainSize, grainGain);
      this._outW        += synthHop;
      this._synthRemain += synthHop;
    }
    _runYIN() {
      const base = this._inW - this._latency - YIN_W;
      const tMin = this._tMin;
      const tMax = this._tMax;
      let runSum = 0, bestTau = -1, bestD = 1.0;
      for (let tau = 1; tau <= tMax; tau++) {
        let d = 0;
        for (let j = 0; j < YIN_W; j++) {
          const diff = this._inBuf[(base + j)      & PSO_INM]
                     - this._inBuf[(base + j - tau) & PSO_INM];
          d += diff * diff;
        }
        runSum += d;
        if (tau < tMin) continue;
        const dNorm = runSum > 0 ? d * tau / runSum : 1.0;
        if (dNorm < YIN_THR && dNorm < bestD) {
          bestD = dNorm; bestTau = tau;
          if (dNorm < YIN_THR * 0.5) break;
        }
      }
      this._voiced = bestTau > 0;
      if (this._voiced) {
        const raw = Math.max(tMin, Math.min(tMax, bestTau));
        this._lastT0 = Math.round(0.85 * this._lastT0 + 0.15 * raw);
      }
    }
    _findPitchMark(anchor, T0) {
      const half = Math.max(1, Math.round(T0 * 0.25));
      let best = anchor, bestAbs = Infinity;
      for (let i = -half; i <= half; i++) {
        const v = Math.abs(this._inBuf[(anchor + i) & PSO_INM]);
        if (v < bestAbs) { bestAbs = v; best = anchor + i; }
      }
      return best;
    }
    _overlapAdd(start, size, gain) {
      if (size < 2) return;
      const sm1 = size - 1;
      for (let i = 0; i < size; i++) {
        const w = HANN[Math.round(i / sm1 * HTABM1)] * gain;
        this._outBuf[(this._outW + i) & PSO_OUTM] +=
          this._inBuf[(start + i) & PSO_INM] * w;
      }
    }
  }

  registerProcessor('pitch-shifter-ola',   OLAPitchShifter);
  registerProcessor('pitch-shifter-psola', PSOLAPitchShifter);
})();
`;

// ── Loader ────────────────────────────────────────────────────────────────────
// Loads BOTH processors into the AudioContext in a single addModule() call.

let _blobUrl: string | null = null;

export async function loadPitchShifterWorklet(ctx: AudioContext): Promise<void> {
  if (!_blobUrl) {
    const blob = new Blob([COMBINED_WORKLET_CODE], { type: 'application/javascript' });
    _blobUrl = URL.createObjectURL(blob);
  }
  await ctx.audioWorklet.addModule(_blobUrl);
}
