// src/scripts/daf/AnalyticsHeartbeat.ts
// Sends a `daf_active` gtag event every 60 s while audio is genuinely playing.

import type { AudioGraph } from './AudioGraph';

export class AnalyticsHeartbeat {
  private _intervalMs: number;
  private _isActive: () => boolean;
  private _elapsedMs: () => number;
  private _getGraph: () => AudioGraph | null;
  private _getStream: () => MediaStream | null;
  private _intervalId: ReturnType<typeof setInterval> | null = null;

  constructor(
    intervalMs: number,
    isActive: () => boolean,
    elapsedMs: () => number,
    getGraph: () => AudioGraph | null,
    getStream: () => MediaStream | null,
  ) {
    this._intervalMs = intervalMs;
    this._isActive = isActive;
    this._elapsedMs = elapsedMs;
    this._getGraph = getGraph;
    this._getStream = getStream;
  }

  start(): void {
    if (this._intervalId) return;  // already running
    if (!this._isActive()) return;

    this._intervalId = setInterval(() => {
      try {
        if (!this._shouldSend()) return;
        window.sendAnalyticsEvent?.('daf_active', {
          event_category: 'DAF',
          event_label: 'heartbeat',
          daf_usage_s: Math.floor(this._elapsedMs() / 1000),
        });
      } catch (e) {
        console.warn('Analytics heartbeat error:', e);
      }
    }, this._intervalMs);
  }

  stop(): void {
    if (this._intervalId) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }
  }

  // ── private ─────────────────────────────────────────────────────────────────

  private _shouldSend(): boolean {
    if (!this._isActive()) return false;

    const graph = this._getGraph();
    if (!graph || graph.state !== 'running') return false;

    const stream = this._getStream();
    if (!stream) return false;
    const anyEnabled = stream.getAudioTracks?.().some(t => t.enabled !== false);
    if (!anyEnabled) return false;

    if (graph.gainValue <= 0) return false;

    return typeof window.sendAnalyticsEvent === 'function';
  }
}
