// src/scripts/daf/app.ts
// Main DAF application entry point.
// Loaded via a <script> tag in DAFControls.astro — Vite bundles this
// file and all its imports into a single hashed chunk.

import { SITE } from "@constants";
import { DEFAULT_FAF_MODE, type FAFMode } from './PitchShifterWorklet';
import { SpeechProcessor } from './SpeechProcessor';
import { UIController } from './UIController';
// ── Service Worker ──────────────────────────────────────────────────────────

if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker
      .register(`${SITE.base}service-worker.js`)
      .then(r => console.log('Service Worker registered:', r.scope))
      .catch(e => console.warn('Service Worker registration failed:', e));
  });
}

// ── Wake Lock ────────────────────────────────────────────────────────────────

let wakeLock: WakeLockSentinel | null = null;

async function requestWakeLock(): Promise<void> {
  try {
    if ('wakeLock' in navigator) {
      wakeLock = await navigator.wakeLock.request('screen');
      wakeLock.addEventListener('release', () => { wakeLock = null; });
    }
  } catch (e) {
    console.error('Wake Lock request failed:', (e as Error).message);
  }
}

function releaseWakeLock(): void {
  wakeLock?.release().then(() => { wakeLock = null; }).catch(console.error);
}

// ── Pending device preference ─────────────────────────────────────────────────
let pendingDeviceId: string | null = null;

// ── Audio constraint state ────────────────────────────────────────────────────
let echoCancel = false;
let noiseSuppress = false;

// ── Voice profile state ───────────────────────────────────────────────────────
let voicePitchFloor = 120; // 'normal' default

// ── FAF mode state ────────────────────────────────────────────────────────────
let fafMode: FAFMode = DEFAULT_FAF_MODE;
type PitchUnit = 'semitones' | 'cents';
let pitchUnit: PitchUnit = 'semitones';
let centsRange: 300 | 800 = 800;

/** Format the pitch shift display label based on raw slider value and unit. */
function formatPitchLabel(rawVal: number, unit: PitchUnit): string {
  if (rawVal === 0) return 'Off';
  const abs  = Math.abs(rawVal);
  const sign = rawVal > 0 ? '+' : '-';
  if (unit === 'semitones') {
    return `${sign}${abs} ${abs === 1 ? 'semitone' : 'semitones'}`;
  }
  return `${sign}${abs} ${abs === 1 ? 'cent' : 'cents'}`;
}

/** Convert raw slider value to semitones for AudioGraph. */
function toSemitones(rawVal: number, unit: PitchUnit): number {
  return unit === 'cents' ? rawVal / 100 : rawVal;
}

// ── Multi-FAF state ───────────────────────────────────────────────────────────
// multiFAFValues holds up to 4 per-signal semitone values (persisted across
// count changes so adjustments aren't lost when adding/removing signals).
// Default spread: symmetric ±4 st for 2 signals; taper for 3/4.

let multiFAFEnabled = false;
// FAF starts as 'single' — singleFAFSection and pitchUnitSection are shown by default in HTML
let multiFAFCount = 2;
const multiFAFValues = [4, -4, 0, -4]; // indices 0-3; only first `multiFAFCount` are active

function getActiveFAFSemitones(): number[] {
  return multiFAFValues.slice(0, multiFAFCount);
}

// ── Page-level events ────────────────────────────────────────────────────────

document.addEventListener('visibilitychange', () => {
  const visible = document.visibilityState === 'visible';
  window.sendAnalyticsEvent?.('page_visibility', {
    visibility: visible ? 'visible' : 'hidden',
  });
  if (visible && window.speechProcessor) {
    window.speechProcessor.attemptResumeAudio();
    if (!wakeLock) requestWakeLock();
  }
});

window.addEventListener('beforeunload', () => {
  window.speechProcessor?.stop();
  releaseWakeLock();
  window.sendAnalyticsEvent?.('session_end');
});

// ── DAF toggle ───────────────────────────────────────────────────────────────

window.toggleDAF = async function (): Promise<void> {
  const isStarting = !window.speechProcessor?.isRunning;

  window.sendAnalyticsEvent?.(isStarting ? 'start_daf' : 'stop_daf', {
    event_category: 'user_action',
    event_label: isStarting ? 'DAF Started' : 'DAF Stopped',
  });

  if (isStarting) {
    window.speechProcessor = new SpeechProcessor();

    // Seed config from current slider values
    const delaySlider = document.getElementById('delaySlider') as HTMLInputElement | null;
    const gainSlider  = document.getElementById('inputGainSlider') as HTMLInputElement | null;
    const pitchSlider = document.getElementById('pitchShiftSlider') as HTMLInputElement | null;

    window.speechProcessor.config.delayTime = Number(delaySlider?.value ?? 200);
    window.speechProcessor.config.gain      = Number(gainSlider?.value ?? 1);

    if (multiFAFEnabled) {
      window.speechProcessor.config.multiFAFSemitones = getActiveFAFSemitones();
      window.speechProcessor.config.pitchShift = 0;
    } else {
      // Single FAF (or Off if slider is at 0)
      window.speechProcessor.config.multiFAFSemitones = [];
      window.speechProcessor.config.pitchShift = toSemitones(Number(pitchSlider?.value ?? 0), pitchUnit);
    }

    // Apply device preference set via dropdown before session started
    if (pendingDeviceId) {
      window.speechProcessor.setPreferredDevice(pendingDeviceId);
      pendingDeviceId = null;
    }

    // Seed audio constraints — before start() so no restart triggered
    window.speechProcessor.seedAudioConstraints(echoCancel, noiseSuppress);

    // Seed voice profile
    window.speechProcessor.config.pitchFloor = voicePitchFloor;
    window.speechProcessor.config.fafMode    = fafMode;

    requestWakeLock();

    try {
      await window.speechProcessor.start();
    } catch {
      // Error status already set inside SpeechProcessor._handleStartError
    }
  } else {
    await window.speechProcessor?.stop();
    window.speechProcessor = undefined;
    releaseWakeLock();
  }
};

// ── DOMContentLoaded setup ───────────────────────────────────────────────────

document.addEventListener('DOMContentLoaded', () => {
  const statusEl   = document.getElementById('statusMessage');
  const delaySlider = document.getElementById('delaySlider')      as HTMLInputElement | null;
  const gainSlider  = document.getElementById('inputGainSlider')  as HTMLInputElement | null;
  const pitchSlider = document.getElementById('pitchShiftSlider') as HTMLInputElement | null;

  statusEl?.classList.add('status-default');

  // ── Seed display values ────────────────────────────────────────────────────
  if (delaySlider) {
    const el = document.getElementById('delayValue');
    if (el) el.textContent = `${delaySlider.value} ms`;
  }
  if (gainSlider) {
    const el = document.getElementById('inputGainValue');
    if (el) el.textContent = `${gainSlider.value}x`;
  }
  if (pitchSlider) {
    const el = document.getElementById('pitchShiftValue');
    if (el) el.textContent = formatPitchLabel(Number(pitchSlider.value), pitchUnit);
  }

  // ── Core slider listeners ──────────────────────────────────────────────────
  delaySlider?.addEventListener('input', e => {
    const val = Number((e.target as HTMLInputElement).value);
    const target = e.target as HTMLInputElement;
    target.setAttribute('aria-valuenow', String(val));
    target.setAttribute('aria-valuetext', `${val} milliseconds`);
    // Always update the visible label — even when DAF is not running
    const dispEl = document.getElementById('delayValue');
    if (dispEl) dispEl.textContent = `${val} ms`;
    window.speechProcessor?.updateDelayTime(val);
    window.sendAnalyticsEvent?.('adjust_delay', { current_delay_ms: val },
      { debounce: true, debounceMs: 5000 });
  });

  gainSlider?.addEventListener('input', e => {
    const val = Number((e.target as HTMLInputElement).value);
    (e.target as HTMLInputElement).setAttribute('aria-valuenow', String(val));
    (e.target as HTMLInputElement).setAttribute('aria-valuetext', `${val}x`);
    // Always update the visible label — even when DAF is not running
    const dispEl = document.getElementById('inputGainValue');
    if (dispEl) dispEl.textContent = `${val}x`;
    window.speechProcessor?.updateGain(val);
    window.sendAnalyticsEvent?.('adjust_input_gain', { current_input_gain: val },
      { debounce: true, debounceMs: 5000 });
  });

  pitchSlider?.addEventListener('input', e => {
    const rawVal = Number((e.target as HTMLInputElement).value);
    const label  = formatPitchLabel(rawVal, pitchUnit);
    const semitones = toSemitones(rawVal, pitchUnit);
    const el = document.getElementById('pitchShiftValue');
    if (el) el.textContent = label;
    (e.target as HTMLInputElement).setAttribute('aria-valuenow',  String(rawVal));
    (e.target as HTMLInputElement).setAttribute('aria-valuetext', label);
    window.speechProcessor?.updatePitchShift(semitones);
    window.sendAnalyticsEvent?.('adjust_pitch_shift', { semitones },
      { debounce: true, debounceMs: 5000 });
  });

  // ── Generic ModeSelector wiring helper ────────────────────────────────────
  function activateModeBtn(group: string, value: string) {
    document.querySelectorAll<HTMLButtonElement>(
      `.mode-btn[data-group="${group}"]`
    ).forEach(b => {
      const isActive = b.dataset.value === value;
      b.classList.toggle('mode-btn--active', isActive);
      b.setAttribute('aria-pressed', String(isActive));
    });
  }

  // ── Initial DOM state: FAF defaults to 'single' ───────────────────────────
  activateModeBtn('faf-type', 'single');

  document.querySelectorAll<HTMLButtonElement>('.mode-btn[data-group]').forEach(btn => {
    btn.addEventListener('click', () => {
      const group = btn.dataset.group!;
      const value = btn.dataset.value!;

      switch (group) {

        // ── FAF type: Off / Single / Multi ──────────────────────────────────
        case 'faf-type': {
          // Derive current FAF type from module state, not slider value,
          // to avoid false early-returns when slider has a stale non-zero value.
          const singleSection = document.getElementById('singleFAFSection');
          const currentlyShowingSingle = singleSection && !singleSection.hidden;
          const prev = multiFAFEnabled ? 'multi' : (currentlyShowingSingle ? 'single' : 'off');
          if (value === prev) return;
          activateModeBtn('faf-type', value);

          const multiSection  = document.getElementById('multiFAFSection');
          const unitSection   = document.getElementById('pitchUnitSection');
          const offSection    = document.getElementById('offFAFSection');

          if (value === 'off') {
            multiFAFEnabled = false;
            if (offSection)    offSection.hidden    = false;
            singleSection && (singleSection.hidden = true);
            multiSection  && (multiSection.hidden  = true);
            if (unitSection) unitSection.hidden = true;
            if (pitchSlider) { pitchSlider.value = '0'; }
            window.speechProcessor?.updateMultiFAFNodes([]);
            window.speechProcessor?.updatePitchShift(0);
          } else if (value === 'single') {
            multiFAFEnabled = false;
            if (offSection)    offSection.hidden    = true;
            singleSection && (singleSection.hidden = false);
            multiSection  && (multiSection.hidden  = true);
            if (unitSection) unitSection.hidden = false;
            window.speechProcessor?.updateMultiFAFNodes([]);
            const rawVal = Number(pitchSlider?.value ?? 0);
            window.speechProcessor?.updatePitchShift(toSemitones(rawVal, pitchUnit));
          } else { // multi
            multiFAFEnabled = true;
            if (offSection)    offSection.hidden    = true;
            singleSection && (singleSection.hidden = true);
            multiSection  && (multiSection.hidden  = false);
            if (unitSection) unitSection.hidden = true;
            window.speechProcessor?.updateMultiFAFNodes(getActiveFAFSemitones());
          }
          window.sendAnalyticsEvent?.('faf_type_change', { value });
          break;
        }

        // ── FAF signal count ─────────────────────────────────────────────────
        case 'faf-count': {
          const count = Number(value);
          if (!count || count === multiFAFCount) return;
          multiFAFCount = count;
          activateModeBtn('faf-count', value);
          renderFAFSignalSliders();
          if (multiFAFEnabled) {
            window.speechProcessor?.updateMultiFAFNodes(getActiveFAFSemitones());
          }
          window.sendAnalyticsEvent?.('multi_faf_count_change', { count });
          break;
        }

        // ── Pitch unit ───────────────────────────────────────────────────────
        case 'pitch-unit': {
          const newUnit = value as PitchUnit;
          if (newUnit === pitchUnit) return;
          const currentSemitones = pitchSlider
            ? toSemitones(Number(pitchSlider.value), pitchUnit)
            : 0;
          pitchUnit = newUnit;
          activateModeBtn('pitch-unit', value);

          // Show/hide cents range selector
          const centsRangeEl = document.getElementById('centsRangeSelector');
          if (centsRangeEl) centsRangeEl.hidden = (newUnit === 'semitones');

          // Enable/disable cents range buttons
          document.querySelectorAll<HTMLButtonElement>('.mode-btn[data-group="cents-range"]')
            .forEach(b => { b.disabled = (newUnit === 'semitones'); });
          if (pitchSlider) {
            if (newUnit === 'semitones') {
              const semVal = Math.round(Math.max(-8, Math.min(8, currentSemitones)));
              pitchSlider.min = '-8'; pitchSlider.max = '8'; pitchSlider.step = '1';
              pitchSlider.value = String(semVal);
              pitchSlider.setAttribute('aria-valuemin', '-8');
              pitchSlider.setAttribute('aria-valuemax', '8');
            } else {
              const maxC = centsRange;
              const cv   = Math.round(Math.max(-maxC, Math.min(maxC, currentSemitones * 100)));
              pitchSlider.min = String(-maxC); pitchSlider.max = String(maxC); pitchSlider.step = '1';
              pitchSlider.value = String(cv);
              pitchSlider.setAttribute('aria-valuemin', String(-maxC));
              pitchSlider.setAttribute('aria-valuemax', String(maxC));
            }
            const newRaw = Number(pitchSlider.value);
            const newLabel = formatPitchLabel(newRaw, newUnit);
            const el = document.getElementById('pitchShiftValue');
            if (el) el.textContent = newLabel;
            pitchSlider.setAttribute('aria-valuenow',  String(newRaw));
            pitchSlider.setAttribute('aria-valuetext', newLabel);
            window.speechProcessor?.updatePitchShift(toSemitones(newRaw, newUnit));
          }
          break;
        }

        // ── Cents range ──────────────────────────────────────────────────────
        case 'cents-range': {
          const newRange = Number(value) as 300 | 800;
          if (!newRange || newRange === centsRange || pitchUnit !== 'cents') return;
          centsRange = newRange;
          activateModeBtn('cents-range', value);
          if (pitchSlider) {
            const clamped = Math.max(-newRange, Math.min(newRange, Number(pitchSlider.value)));
            pitchSlider.min = String(-newRange); pitchSlider.max = String(newRange);
            pitchSlider.value = String(clamped);
            pitchSlider.setAttribute('aria-valuemin', String(-newRange));
            pitchSlider.setAttribute('aria-valuemax', String(newRange));
            const label = formatPitchLabel(clamped, 'cents');
            const el = document.getElementById('pitchShiftValue');
            if (el) el.textContent = label;
            pitchSlider.setAttribute('aria-valuenow',  String(clamped));
            pitchSlider.setAttribute('aria-valuetext', label);
            window.speechProcessor?.updatePitchShift(clamped / 100);
          }
          break;
        }

        // ── FAF processing mode ──────────────────────────────────────────────
        case 'faf-mode': {
          const newMode = value as FAFMode;
          if (newMode === fafMode) return;
          fafMode = newMode;
          activateModeBtn('faf-mode', value);
          syncVoiceBtnsDisabled(newMode);
          window.speechProcessor?.updateFAFMode(newMode);
          window.sendAnalyticsEvent?.('faf_mode_change', { mode: newMode });
          break;
        }

        // ── Voice type ───────────────────────────────────────────────────────
        case 'voice-type': {
          const floor = Number(value);
          if (!floor || floor === voicePitchFloor) return;
          voicePitchFloor = floor;
          activateModeBtn('voice-type', value);
          window.speechProcessor?.updateVoiceProfile(floor);
          window.sendAnalyticsEvent?.('voice_profile_change', { pitchFloor: floor });
          break;
        }
        // ── Benchmark explanation mode ────────────────────────────────────────
        case 'bench-mode': {
          const container = document.getElementById('benchmarkContainer');
          if (!container) return;
          activateModeBtn('bench-mode', value);
          container.className = container.className
            .replace(/\bbench-mode--\w+/g, '')
            .trim() + ` bench-mode--${value}`;
          break;
        }

      }
    });
  });

  const advancedToggle = document.getElementById('advancedToggle') as HTMLButtonElement | null;
  const advancedPanel  = document.getElementById('advancedPanel');

  advancedToggle?.addEventListener('click', () => {
    const on = advancedToggle.getAttribute('aria-checked') === 'true';
    advancedToggle.setAttribute('aria-checked', String(!on));
    advancedToggle.classList.toggle('toggle-switch--on', !on);
    if (advancedPanel) advancedPanel.hidden = on;
  });

  // ── Constraint toggles (ToggleSwitch) ─────────────────────────────────────
  const makeToggleSwitch = (
    id: string,
    getter: () => boolean,
    setter: (v: boolean) => void,
    onChange: (v: boolean) => void,
  ) => {
    const btn = document.getElementById(id) as HTMLButtonElement | null;
    if (!btn) return;
    btn.addEventListener('click', () => {
      const next = !(getter());
      setter(next);
      btn.setAttribute('aria-checked', String(next));
      btn.classList.toggle('toggle-switch--on', next);
      onChange(next);
    });
  };

  makeToggleSwitch('echoCancelToggle',
    () => echoCancel, v => { echoCancel = v; },
    () => window.speechProcessor?.updateAudioConstraints(echoCancel, noiseSuppress)
            .catch(e => console.warn('Constraint update failed:', e))
  );
  makeToggleSwitch('noiseSuppressToggle',
    () => noiseSuppress, v => { noiseSuppress = v; },
    () => window.speechProcessor?.updateAudioConstraints(echoCancel, noiseSuppress)
            .catch(e => console.warn('Constraint update failed:', e))
  );

  // sync voice btns disabled state
  const syncVoiceBtnsDisabled = (mode: FAFMode) => {
    document.querySelectorAll<HTMLButtonElement>('.mode-btn[data-group="voice-type"]')
      .forEach(b => {
        b.disabled = (mode === 'ola');
        b.title    = mode === 'ola' ? 'Voice type only applies in High-Fidelity mode' : '';
      });

    if (mode === 'ola') {
      // When voice buttons are disabled, clicking them should glow the
      // High-Fidelity mode button to hint the user what to click.
      document.querySelectorAll<HTMLButtonElement>('.mode-btn[data-group="voice-type"]')
        .forEach(b => {
          b.addEventListener('click', glowHighFidelityBtn, { capture: true });
        });
    } else {
      document.querySelectorAll<HTMLButtonElement>('.mode-btn[data-group="voice-type"]')
        .forEach(b => {
          b.removeEventListener('click', glowHighFidelityBtn, { capture: true });
        });
    }
  };

  function glowHighFidelityBtn() {
    const hfBtn = document.querySelector<HTMLButtonElement>(
      '.mode-btn[data-group="faf-mode"][data-value="psola"]'
    );
    if (!hfBtn) return;
    hfBtn.classList.remove('mode-btn--glow');
    void hfBtn.offsetWidth; // reflow to restart animation
    hfBtn.classList.add('mode-btn--glow');
    hfBtn.addEventListener('animationend', () => hfBtn.classList.remove('mode-btn--glow'), { once: true });
  }
  syncVoiceBtnsDisabled(fafMode);

  // ── Signal sliders initial render ──────────────────────────────────────────
  renderFAFSignalSliders();

  // ── Benchmark ──────────────────────────────────────────────────────────────
  const benchmarkBtn       = document.getElementById('benchmarkBtn') as HTMLButtonElement | null;
  const benchmarkContainer = document.getElementById('benchmarkContainer');

  /** Populate a [data-bench] span with a value. */
  function setBench(key: string, value: string): void {
    const el = benchmarkContainer?.querySelector<HTMLElement>(`[data-bench="${key}"]`);
    if (el) el.textContent = value;
  }

  benchmarkBtn?.addEventListener('click', async () => {
    if (!window.speechProcessor?.isRunning) {
      // Show inline red info box below the button instead of just a status message
      const existing = document.getElementById('benchmarkInactiveMsg');
      if (!existing) {
        const msg = document.createElement('p');
        msg.id = 'benchmarkInactiveMsg';
        msg.className = 'bench-inactive-msg';
        msg.innerHTML = `Measures active session. <a href="#dafButton" class="bench-inactive-link" id="benchmarkStartLink">Start auditory feedback</a> first.`;
        benchmarkBtn.insertAdjacentElement('afterend', msg);
        // Clicking the link scrolls to and highlights the DAF button
        document.getElementById('benchmarkStartLink')?.addEventListener('click', e => {
          e.preventDefault();
          const btn = document.getElementById('dafButton');
          if (btn) {
            btn.scrollIntoView({ behavior: 'smooth', block: 'center' });
            btn.focus();
            btn.classList.add('btn--highlight');
            setTimeout(() => btn.classList.remove('btn--highlight'), 1800);
          }
        });
        // Auto-remove when DAF starts
        const observer = new MutationObserver(() => {
          if (window.speechProcessor?.isRunning) {
            msg.remove();
            observer.disconnect();
          }
        });
        observer.observe(document.getElementById('statusMessage') ?? document.body,
          { childList: true, subtree: true, characterData: true });
      }
      return;
    }

    benchmarkBtn.disabled = true;
    benchmarkBtn.textContent = 'Running…';

    try {
      const r = await window.speechProcessor.runBenchmark();

      const jitterRating =
        r.jitter.stddevMs < 0.5  ? '✅ Excellent' :
        r.jitter.stddevMs < 1.5  ? '🟡 Good' :
        r.jitter.stddevMs < 3.0  ? '🟠 Moderate' : '🔴 High';

      // Populate each value span individually — no innerHTML
      setBench('sampleRate',       r.sampleRate.toLocaleString() + ' Hz');
      setBench('estimatedBuffer',  r.estimatedBufferSamples + ' samples');
      setBench('baseLatency',      r.baseLatencyMs > 0 ? r.baseLatencyMs + ' ms' : '0 ms (not reported by this browser)');
      setBench('outputLatency',    r.outputLatencyMs + ' ms');
      setBench('inputLatency',     r.inputLatencyMs !== null ? r.inputLatencyMs + ' ms' : 'n/a');
      setBench('fafLatency',       r.fafLatencyMs > 0 ? r.fafLatencyMs + ' ms' : 'off');
      setBench('totalFloor',       r.totalFloorMs + ' ms');
      setBench('quantumMs',        r.quantumMs + ' ms');
      setBench('jitterSamples',    String(r.jitter.samples));
      setBench('minDrift',         r.jitter.minDriftMs + ' ms');
      setBench('maxDrift',         r.jitter.maxDriftMs + ' ms');
      setBench('meanDrift',        r.jitter.meanDriftMs + ' ms');
      setBench('p95Drift',         r.jitter.p95DriftMs + ' ms');
      setBench('jitterStddev',     r.jitter.stddevMs + ' ms — ');
      setBench('jitterRating',     jitterRating);

      // Show high-jitter warning tip when stddev >= 3 ms
      const jitterWarn = document.getElementById('jitterHighWarn');
      if (jitterWarn) jitterWarn.hidden = r.jitter.stddevMs < 3.0;

      if (benchmarkContainer) benchmarkContainer.hidden = false;

      window.sendAnalyticsEvent?.('benchmark_run', {
        total_floor_ms:   r.totalFloorMs,
        jitter_stddev_ms: r.jitter.stddevMs,
        sample_rate:      r.sampleRate,
      });
    } catch (err) {
      new UIController().updateStatus(
        `Benchmark failed: ${(err as Error).message}`, 'error',
      );
    } finally {
      benchmarkBtn.disabled = false;
      benchmarkBtn.textContent = 'Run Benchmark';
    }
  });

  // ── Benchmark explanation mode ─────────────────────────────────────────────
  // Handled by the generic mode-btn dispatcher above via data-group="bench-mode"

  // ── DAF button ─────────────────────────────────────────────────────────────
  document.getElementById('dafButton')?.addEventListener('click', () => window.toggleDAF());
  statusEl?.addEventListener('click', () => {
    if (window.speechProcessor) {
      window.speechProcessor.attemptResumeAudio();
      window.sendAnalyticsEvent?.('resume_audio_attempt');
    }
  });

  // ── Device dropdown ────────────────────────────────────────────────────────
  const deviceSelect = document.getElementById('deviceSelect') as HTMLSelectElement | null;

  const ui = new UIController();

  navigator.mediaDevices?.enumerateDevices().then(all => {
    const inputs = all.filter(d => d.kind === 'audioinput');
    if (inputs.some(d => d.label)) {
      // Permission already granted — populate with real labels now
      const firstId = inputs[0]?.deviceId ?? null;
      ui.populateDeviceDropdown(inputs, firstId);
      if (firstId && !pendingDeviceId) pendingDeviceId = firstId;
    } else {
      // No labels yet — permission not granted; show explanatory placeholder
      ui.setDeviceDropdownPending();
    }
  }).catch(() => {
    ui.setDeviceDropdownPending();
  });

  deviceSelect?.addEventListener('change', e => {
    const deviceId = (e.target as HTMLSelectElement).value;
    if (!deviceId) return;

    if (window.speechProcessor) {
      window.speechProcessor.selectAudioDevice(deviceId)
        .catch(err => console.warn('Device select failed:', err));
    } else {
      // DAF not running — store for pickup when Start DAF is clicked
      pendingDeviceId = deviceId;
    }

    window.sendAnalyticsEvent?.('device_dropdown_select', { deviceId });
  });
});

// ── Signal slider rendering ───────────────────────────────────────────────────
// Generates per-signal sliders inside #fafSignalSliders and wires their events.
// Called on init and whenever the signal count changes.

function renderFAFSignalSliders(): void {
  const container = document.getElementById('fafSignalSliders');
  if (!container) return;

  container.innerHTML = '';

  for (let i = 0; i < multiFAFCount; i++) {
    const val   = multiFAFValues[i] ?? 0;
    // Signal sliders are always in semitones. 0 = unshifted passthrough (not off).
    const label = val === 0 ? '0 st (unshifted)' : `${val > 0 ? '+' : ''}${val} st`;

    const wrapper = document.createElement('div');
    wrapper.className = 'faf-signal-row';
    wrapper.innerHTML = `
      <label class="faf-signal-label" for="fafSignal${i}">
        Signal ${i + 1}:
        <span id="fafSignalValue${i}" class="slider-value">${label}</span>
      </label>
      <input
        type="range"
        id="fafSignal${i}"
        class="faf-signal-slider"
        min="-8" max="8" step="1" value="${val}"
        aria-valuemin="-8" aria-valuemax="8"
        aria-valuenow="${val}" aria-valuetext="${label}"
        data-index="${i}"
      />
    `;
    container.appendChild(wrapper);

    const slider = wrapper.querySelector<HTMLInputElement>('.faf-signal-slider')!;
    slider.addEventListener('input', e => {
      const idx  = Number((e.target as HTMLInputElement).dataset.index);
      const v    = Number((e.target as HTMLInputElement).value);
      multiFAFValues[idx] = v;
      const lbl  = v === 0 ? '0 st (unshifted)' : `${v > 0 ? '+' : ''}${v} st`;
      const span = document.getElementById(`fafSignalValue${idx}`);
      if (span) span.textContent = lbl;
      (e.target as HTMLInputElement).setAttribute('aria-valuenow',  String(v));
      (e.target as HTMLInputElement).setAttribute('aria-valuetext', lbl);

      if (multiFAFEnabled) {
        window.speechProcessor?.updateMultiFAFNodes(getActiveFAFSemitones());
      }
      window.sendAnalyticsEvent?.('adjust_multi_faf_signal', { index: idx, semitones: v },
        { debounce: true, debounceMs: 3000 });
    });
  }
}
