// src/scripts/daf/SpeechProcessor.ts
// Orchestrator only. Wires AudioGraph, DeviceManager, SessionTimer,
// AnalyticsHeartbeat, and UIController together.

import { AnalyticsHeartbeat } from './AnalyticsHeartbeat';
import { AudioGraph } from './AudioGraph';
import { DeviceManager } from './DeviceManager';
import { ErrorReporter } from './ErrorReporter';
import { SessionTimer } from './SessionTimer';
import { UIController } from './UIController';
import { DEFAULT_FAF_MODE, type FAFMode } from './PitchShifterWorklet';

interface DAFConfig {
  delayTime: number;
  gain: number;
  pitchShift: number;
  multiFAFSemitones: number[];
  pitchFloor: number;
  fafMode: FAFMode;
}

export class SpeechProcessor {
  config: DAFConfig = { delayTime: 200, gain: 1, pitchShift: 0, multiFAFSemitones: [], pitchFloor: 120, fafMode: DEFAULT_FAF_MODE };

  private _ui: UIController;
  private _reporter: ErrorReporter;
  private _devices: DeviceManager;
  private _timer: SessionTimer;
  private _heartbeat: AnalyticsHeartbeat;
  private _graph: AudioGraph | null = null;
  private _stream: MediaStream | null = null;

  private _resumeAttempts = 0;
  private _maxResumeAttempts = 5;
  private _isAppVisible = document.visibilityState === 'visible';

  private _onVisibilityChange: () => void;
  private _onFreeze: () => void;
  private _onResume: () => void;
  private _onDocClick: () => void;

  constructor() {
    this._ui = new UIController();
    this._reporter = new ErrorReporter();
    this._devices = new DeviceManager(this._ui, this._reporter);
    this._timer = new SessionTimer();

    this._heartbeat = new AnalyticsHeartbeat(
      60_000,
      () => this.isRunning,
      () => this._timer.elapsedMs,
      () => this._graph,
      () => this._stream,
    );

    this._onVisibilityChange = this._handleVisibilityChange.bind(this);
    this._onFreeze = this._handleFreeze.bind(this);
    this._onResume = this._handleResume.bind(this);
    this._onDocClick = this._handleDocClick.bind(this);

    document.addEventListener('visibilitychange', this._onVisibilityChange);
    if ('onfreeze' in document) document.addEventListener('freeze', this._onFreeze);
    if ('onresume' in document) document.addEventListener('resume', this._onResume);
    document.addEventListener('click', this._onDocClick);

    this._ui.updateDeviceUI('Click "Start DAF" to select your microphone', false);
  }

  // ── public API ───────────────────────────────────────────────────────────────

  get isRunning(): boolean {
    return !!this._graph && this._graph.state === 'running';
  }

  get measuredFloorMs(): number | null {
    return this._graph?.measuredFloorMs ?? null;
  }

  get fafLatencyMs(): number {
    return this._graph?.fafLatencyMs ?? 0;
  }

  async start(preAcquiredStream: MediaStream | null = null): Promise<void> {
    this._ui.updateStatus('Starting audio connection…', 'loading');
    try {
      const { stream, sampleRate } = await this._devices.acquireStream(preAcquiredStream);
      this._stream = stream;

      this._graph = new AudioGraph(sampleRate);
      this._graph.pitchFloor = this.config.pitchFloor;
      this._graph.fafMode    = this.config.fafMode;
      this._graph.onStateChange(state => this._onGraphStateChange(state));
      this._graph.connect(stream, this.config);

      if (this._graph.state === 'running') {
        this._graph.measureLatencyFloor(this._stream);
        this._refreshDelayDisplay();

        // Some browsers (notably Chrome) report outputLatency as 0 or stale
        // immediately after context creation, then update it asynchronously.
        // Re-read after 200 ms to get the stabilised value so the "effective"
        // display is accurate without requiring a full benchmark run.
        setTimeout(() => {
          if (this.isRunning && this._graph) {
            this._graph.measureLatencyFloor(this._stream);
            this._refreshDelayDisplay();
          }
        }, 200);
      }

      this._ui.updateControls(true);
      this._ui.updateStatus('Auditory Feedback Active', 'success');

      if (this._timer.elapsedMs > 0) {
        this._timer.resume();
      } else {
        this._timer.start();
      }
      this._heartbeat.start();

      await this._devices.enumerate();
      this._devices.initChangeListener(
        () => this._devices.enumerate(),
        () => this.isRunning,
      );
    } catch (err) {
      this._handleStartError(err);
      throw err;
    }
  }

  async stop({ preserveTimer = false } = {}): Promise<void> {
    this._heartbeat.stop();

    if (preserveTimer) {
      this._timer.pause();
    } else {
      this._timer.stop();
    }

    this._devices.releaseStream(this._stream);
    this._stream = null;

    await this._graph?.close();
    this._graph = null;

    this._resumeAttempts = 0;
    this._ui.updateStatus('Auditory Feedback Stopped', 'info');
    this._ui.updateControls(false);
    this._ui.updateDeviceUI('Click "Start DAF" to select your microphone', false);
  }

  async restartWithNewDevice(preAcquiredStream: MediaStream | null = null): Promise<boolean> {
    const saved = { ...this.config, multiFAFSemitones: [...this.config.multiFAFSemitones] };
    await this.stop({ preserveTimer: true });
    await new Promise(r => setTimeout(r, 300));
    this.config = saved;
    await this.start(preAcquiredStream);
    return true;
  }

  updateDelayTime(ms: number): void {
    this.config.delayTime = ms;
    this._graph?.setDelayTime(ms);
    this._refreshDelayDisplay();
  }

  updateGain(value: number): void {
    this.config.gain = value;
    this._graph?.setGain(value);
    this._ui.updateDisplay('inputGainValue', `${value}x`);
  }

  /** Alias kept for backward compatibility. */
  updateInputGain(value: number): void { this.updateGain(value); }

  /**
   * Update single-FAF pitch shift.
   * Only takes effect when multi-FAF is not active (multiFAFSemitones is empty).
   */
  updatePitchShift(semitones: number): void {
    this.config.pitchShift = semitones;
    // Display is managed by app.ts, which knows the current unit (semitones/cents).
    this._refreshDelayDisplay();
    this._graph?.setFAFSemitones(semitones)
      .then(() => this._refreshDelayDisplay())
      .catch(e => console.warn('FAF update failed:', e));
  }

  /**
   * Update multi-FAF nodes.
   * semitones = [] → bypass all FAF (multi-FAF off).
   * semitones = [a, b, …] → N parallel pitch-shifted signals.
   *
   * Persists across device-switch restarts via config.multiFAFSemitones.
   */
  updateMultiFAFNodes(semitones: number[]): void {
    this.config.multiFAFSemitones = semitones;

    // Optimistic display refresh
    this._refreshDelayDisplay();

    // Accurate refresh after graph is rewired
    this._graph?.setFAFNodes(semitones)
      .then(() => this._refreshDelayDisplay())
      .catch(e => console.warn('Multi-FAF update failed:', e));
  }

  /**
   * Store a device preference before a session starts.
   * Called when the user picks from the dropdown while DAF is not running.
   * The next call to start() will use this deviceId.
   */
  setPreferredDevice(deviceId: string): void {
    this._devices.selectedDeviceId = deviceId;
  }

  /**
   * Set audio constraints before a session starts (no restart triggered).
   * For mid-session changes use updateAudioConstraints() instead.
   */
  /**
   * Update the voice profile (pitch floor).
   * If FAF is active, rebuilds FAF nodes with the new pitch floor so
   * the new latency takes effect immediately.
   */
  updateVoiceProfile(pitchFloor: number): void {
    this.config.pitchFloor = pitchFloor;
    if (this._graph) {
      this._graph.pitchFloor = pitchFloor;
      const semitones = this.config.multiFAFSemitones.length
        ? this.config.multiFAFSemitones
        : this.config.pitchShift !== 0 ? [this.config.pitchShift] : [];
      if (semitones.length > 0) {
        // Force a full teardown+rebuild so processorOptions.pitchFloor takes effect.
        // The setFAFNodes fast-path (same count → param update only) would leave
        // the existing nodes running at the old pitch floor.
        this._graph.setFAFNodes([])          // teardown
          .then(() => this._graph?.setFAFNodes(semitones))  // rebuild with new pitchFloor
          .then(() => this._refreshDelayDisplay())
          .catch(e => console.warn('Voice profile FAF rebuild failed:', e));
      }
      this._refreshDelayDisplay();
    }
  }

  /**
   * Switch between OLA (Low Latency) and PSOLA (High-Fidelity) modes.
   * If FAF is active, forces a full teardown + rebuild so nodes use the
   * correct processor name.
   */
  updateFAFMode(mode: FAFMode): void {
    this.config.fafMode = mode;
    if (this._graph) {
      this._graph.fafMode = mode;
      const semitones = this.config.multiFAFSemitones.length
        ? this.config.multiFAFSemitones
        : this.config.pitchShift !== 0 ? [this.config.pitchShift] : [];
      if (semitones.length > 0) {
        this._graph.setFAFNodes([])
          .then(() => this._graph?.setFAFNodes(semitones))
          .then(() => this._refreshDelayDisplay())
          .catch(e => console.warn('FAF mode switch failed:', e));
      }
      this._refreshDelayDisplay();
    }
  }

  seedAudioConstraints(echoCancellation: boolean, noiseSuppression: boolean): void {
    this._devices.echoCancellation = echoCancellation;
    this._devices.noiseSuppression = noiseSuppression;
  }

  /**
   * Update echo cancellation and noise suppression constraints.
   * If DAF is running, restarts the audio stream immediately so the new
   * constraints take effect — same hot-restart path as a device switch.
   */
  async updateAudioConstraints(
    echoCancellation: boolean,
    noiseSuppression: boolean,
  ): Promise<void> {
    this._devices.echoCancellation = echoCancellation;
    this._devices.noiseSuppression = noiseSuppression;
    if (this.isRunning) {
      await this.restartWithNewDevice(null);
    }
  }

  /**
   * Select a specific microphone by device ID.
   * DAF not running → stores preference for next start, no restart.
   * DAF running → acquires new stream and hot-restarts audio.
   */
  async selectAudioDevice(deviceId: string): Promise<void> {
    await this._devices.selectById(
      deviceId,
      this.isRunning,
      stream => this.restartWithNewDevice(stream),
    );
  }

  /**
   * Run a full latency + jitter benchmark.
   * DAF must be active (graph running). Takes ~600 ms.
   */
  async runBenchmark() {
    if (!this._graph) throw new Error('DAF is not running');
    return this._graph.benchmark(this._stream);
  }

  async destroy(): Promise<void> {
    await this.stop();
    this._devices.destroy();
    document.removeEventListener('visibilitychange', this._onVisibilityChange);
    document.removeEventListener('freeze', this._onFreeze);
    document.removeEventListener('resume', this._onResume);
    document.removeEventListener('click', this._onDocClick);
    console.log('SpeechProcessor destroyed');
  }

  // ── audio resume ─────────────────────────────────────────────────────────────

  async attemptResumeAudio(): Promise<void> {
    if (!this._graph || this._graph.state !== 'suspended') return;
    if (this._resumeAttempts >= this._maxResumeAttempts) return;

    this._resumeAttempts++;
    try {
      await this._graph.resume();
      this._resumeAttempts = 0;
    } catch {
      if (this._resumeAttempts > 1) {
        this._reporter.audioResumedAfterRetries(this._resumeAttempts);
      }
      if (this._resumeAttempts < this._maxResumeAttempts) {
        const delay = Math.pow(2, this._resumeAttempts) * 100;
        setTimeout(() => this.attemptResumeAudio(), delay);
      } else {
        this._ui.updateStatus('Audio paused — tap to resume', 'error');
        this._heartbeat.stop();
      }
    }
  }

  // ── private event handlers ────────────────────────────────────────────────────

  private _onGraphStateChange(state: string): void {
    this._notifyServiceWorker('AUDIO_STATE', { state });
    if (state === 'running' && this._graph) {
      this._graph.measureLatencyFloor(this._stream);
      this._refreshDelayDisplay();
    }
    if (state === 'suspended' && this._isAppVisible && this._graph) {
      this.attemptResumeAudio();
    }
  }

  private _handleVisibilityChange(): void {
    this._isAppVisible = document.visibilityState === 'visible';
    this._reporter.visibilityChanged(document.visibilityState);
    this._notifyServiceWorker('VISIBILITY_CHANGE', { isVisible: this._isAppVisible });
    if (this._isAppVisible && this._graph?.state === 'suspended') {
      this.attemptResumeAudio();
    }
  }

  private _handleFreeze(): void { /* graph emits 'suspended' on its own */ }

  private _handleResume(): void {
    if (this._graph?.state === 'suspended') this.attemptResumeAudio();
  }

  private _handleDocClick(): void {
    if (this._graph?.state === 'suspended') this.attemptResumeAudio();
  }

  private _notifyServiceWorker(type: string, data: Record<string, unknown>): void {
    if ('serviceWorker' in navigator && navigator.serviceWorker.controller) {
      navigator.serviceWorker.controller.postMessage({ type, ...data });
    }
  }

  /**
   * Recompute and push the delay display string.
   * Includes hardware floor + FAF worklet latency + intentional delay.
   * Called whenever any latency component changes.
   */
  private _refreshDelayDisplay(): void {
    const ms    = this.config.delayTime;
    const floor = this.measuredFloorMs ?? 0;
    const faf   = this.fafLatencyMs;
    const total = floor + faf;

    const text = total > 5
      ? `${ms} ms (~${Math.round(ms + total)} ms effective)`
      : `${ms} ms`;
    this._ui.updateDisplay('delayValue', text);
  }

  private _handleStartError(err: unknown): void {
    this._heartbeat.stop();
    this._timer.stop();

    const classified = this._reporter.classifyMicError(err);

    this._reporter.audioInitFailed(err, {
      deviceId: this._devices.selectedDeviceId,
      micErrorTag: classified.tag,
      audioContextState: this._graph?.context?.state ?? 'not_initialized',
      availableDeviceCount: this._devices.availableDevices.length,
      hasUserMedia: !!(navigator.mediaDevices?.getUserMedia),
      secureContext: window.isSecureContext,
      preAcquired: false,
    });

    window.sendAnalyticsEvent?.('daf_initialization_error', {
      event_category: 'DAF',
      event_label: classified.tag,
      error_message: (err as Error)?.message ?? '',
    });

    this._ui.updateStatus(classified.message, 'error');
  }
}
