// src/scripts/daf/DeviceManager.ts
// Owns: enumerating audio input devices, selecting a device, and keeping
// the mic dropdown in sync.

import type { ErrorReporter } from './ErrorReporter';
import type { UIController } from './UIController';

type RestartFn = (stream: MediaStream) => Promise<boolean>;

export class DeviceManager {
  availableDevices: MediaDeviceInfo[] = [];
  selectedDeviceId: string | null = null;
  micAccessGranted = false;
  echoCancellation = false;
  noiseSuppression = false;

  private _ui: UIController;
  private _reporter: ErrorReporter;
  private _sampleRate: number | null = null;
  private _currentLabel = '';
  private _initialized = false;
  private _onDeviceChange: (() => void) | null = null;

  constructor(ui: UIController, reporter: ErrorReporter) {
    this._ui = ui;
    this._reporter = reporter;
  }

  // ── microphone access ───────────────────────────────────────────────────────

  async acquireStream(
    preAcquiredStream: MediaStream | null = null,
  ): Promise<{ stream: MediaStream; sampleRate: number | null }> {
    if (preAcquiredStream) {
      this.micAccessGranted = true;
      this._recordTrackMeta(preAcquiredStream.getAudioTracks()[0]!);
      return { stream: preAcquiredStream, sampleRate: this._sampleRate };
    }

    const constraints: MediaStreamConstraints = {
      audio: {
        echoCancellation: this.echoCancellation,
        autoGainControl: false,
        noiseSuppression: this.noiseSuppression,
        channelCount: 1,
        ...(this.selectedDeviceId ? { deviceId: { exact: this.selectedDeviceId } } : {}),
      },
    };

    const stream = await navigator.mediaDevices.getUserMedia(constraints);
    this.micAccessGranted = true;
    this._recordTrackMeta(stream.getAudioTracks()[0]!);

    try {
      const all = await navigator.mediaDevices.enumerateDevices();
      this.availableDevices = all.filter(d => d.kind === 'audioinput');
    } catch (e) {
      console.warn('Could not refresh device list after mic grant:', e);
    }

    return { stream, sampleRate: this._sampleRate };
  }

  releaseStream(stream: MediaStream | null): void {
    if (!stream) return;
    stream.getTracks().forEach(t => { t.stop(); t.enabled = false; });
    this.micAccessGranted = false;
  }

  // ── enumeration ─────────────────────────────────────────────────────────────

  async enumerate(): Promise<MediaDeviceInfo[]> {
    try {
      let tempStream: MediaStream | null = null;
      if (!this.micAccessGranted) {
        try {
          tempStream = await navigator.mediaDevices.getUserMedia({ audio: true });
        } catch { /* proceed without labels */ }
      }

      const all = await navigator.mediaDevices.enumerateDevices();

      if (tempStream) {
        tempStream.getTracks().forEach(t => { try { t.stop(); } catch { /**/ } });
      }

      this.availableDevices = all.filter(d => d.kind === 'audioinput');
      console.log('Audio inputs:', this.availableDevices);

      this._autoSelectHeadphone();
      this._reflectSelectedDeviceInUI();

      // Rebuild dropdown with labelled devices
      this._ui.populateDeviceDropdown(this.availableDevices, this.selectedDeviceId);

      return this.availableDevices;
    } catch (err) {
      console.error('Error enumerating audio devices:', err);
      this._ui.updateDeviceUI('Default microphone', false);
      return [];
    }
  }

  // ── selection ───────────────────────────────────────────────────────────────

  /**
   * Select a specific device by ID.
   *
   * Not running → store preference only (dropdown synced, no restart).
   * Running + restartFn → acquire new stream and restart audio.
   */
  async selectById(
    deviceId: string,
    isRunning: boolean,
    restartFn: RestartFn,
  ): Promise<boolean> {
    if (!deviceId) return false;

    if (!isRunning) {
      // Store preference for next session start
      this.selectedDeviceId = deviceId;
      this._ui.syncDeviceDropdown(deviceId);
      return true;
    }

    // Acquire stream for new device before stopping current one
    let preAcquired: MediaStream | null = null;
    try {
      preAcquired = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: this.echoCancellation, autoGainControl: false,
          noiseSuppression: this.noiseSuppression, channelCount: 1,
          deviceId: { exact: deviceId },
        },
      });
    } catch (err) {
      const { message } = this._reporter.classifyMicError(err);
      this._ui.updateStatus(message, 'error');
      // Revert dropdown to current selection
      this._ui.syncDeviceDropdown(this.selectedDeviceId);
      return false;
    }

    const prev = this.selectedDeviceId;
    this.selectedDeviceId = deviceId;

    const ok = await restartFn(preAcquired);
    if (!ok) {
      this.selectedDeviceId = prev;
      this._ui.syncDeviceDropdown(prev);
      return false;
    }

    const dev = this.availableDevices.find(d => d.deviceId === deviceId);
    const label = dev?.label ?? 'Selected microphone';
    this._ui.updateDeviceUI(label, this._isHeadphoneMic(label));
    this._ui.syncDeviceDropdown(deviceId);
    this._ui.updateStatus(`Switched to: ${label}`, 'success');

    try {
      window.sendAnalyticsEvent?.('device_switch', { to_device_name: label });
    } catch { /**/ }

    return true;
  }

  /**
   * Internal helper used by restartWithNewDevice flow.
   * Direct selection without re-acquiring stream.
   */
  async select(
    deviceId: string,
    restartFn: RestartFn | null = null,
  ): Promise<boolean> {
    if (!deviceId) return false;
    const prev = this.selectedDeviceId;

    if (restartFn) {
      let preAcquired: MediaStream | null = null;
      try {
        preAcquired = await navigator.mediaDevices.getUserMedia({
          audio: {
            echoCancellation: this.echoCancellation, autoGainControl: false,
            noiseSuppression: this.noiseSuppression, channelCount: 1,
            deviceId: { exact: deviceId },
          },
        });
      } catch (err) {
        const { message } = this._reporter.classifyMicError(err);
        this._ui.updateStatus(message, 'error');
        return false;
      }

      this.selectedDeviceId = deviceId;
      const ok = await restartFn(preAcquired);
      if (!ok) this.selectedDeviceId = prev;
      return ok;
    }

    this.selectedDeviceId = deviceId;
    return true;
  }

  // ── change listener ─────────────────────────────────────────────────────────

  initChangeListener(
    onChangeWhileRunning: () => void,
    isRunning: () => boolean,
  ): void {
    if (this._initialized) return;

    this._onDeviceChange = async () => {
      if (isRunning()) await onChangeWhileRunning();
    };

    try {
      navigator.mediaDevices.addEventListener('devicechange', this._onDeviceChange);
    } catch (e) {
      console.warn('Could not attach devicechange listener:', e);
      this._onDeviceChange = null;
    }

    this._initialized = true;
  }

  destroy(): void {
    try {
      if (this._onDeviceChange) {
        navigator.mediaDevices.removeEventListener('devicechange', this._onDeviceChange);
      }
    } catch { /**/ }

    this._initialized = false;
    this._onDeviceChange = null;
    this.availableDevices = [];
    this.selectedDeviceId = null;
    this.micAccessGranted = false;
  }

  // ── private ─────────────────────────────────────────────────────────────────

  private _recordTrackMeta(track: MediaStreamTrack): void {
    if (!track) return;
    type SettingsWithDevice = MediaTrackSettings & { deviceId?: string };
    const settings = track.getSettings?.() as SettingsWithDevice ?? {} as SettingsWithDevice;

    this._sampleRate = settings.sampleRate ?? null;
    if (settings.deviceId) this.selectedDeviceId = settings.deviceId;

    const label = track.label || '';
    this._currentLabel = label || 'Default microphone';
    const isHeadphone = this._isHeadphoneMic(label);
    this._ui.updateDeviceUI(this._currentLabel, isHeadphone);

    this._reporter.micAcquired(settings as MediaTrackSettings, label);
    console.log('Selected microphone settings:', settings);
  }

  private _autoSelectHeadphone(): void {
    const headphone = this.availableDevices.find(d => {
      const l = (d.label || '').toLowerCase();
      if (l.includes('bluetooth') || l.includes('airpod')) return false;
      return l.includes('headphone') || l.includes('headset') || l.includes('earphone');
    });
    if (headphone && this.selectedDeviceId !== headphone.deviceId) {
      this.selectedDeviceId = headphone.deviceId;
      console.log('Auto-selected headphone mic:', headphone.label);
      this._ui.updateDeviceUI(headphone.label, true);
    }
  }

  private _reflectSelectedDeviceInUI(): void {
    if (this.selectedDeviceId) {
      const d = this.availableDevices.find(d => d.deviceId === this.selectedDeviceId);
      if (d) {
        this._ui.updateDeviceUI(d.label, this._isHeadphoneMic(d.label));
        this._ui.syncDeviceDropdown(d.deviceId);
        return;
      }
    }
    const fallback =
      this.availableDevices.find(d => d.deviceId === 'default' || d.deviceId === '') ??
      this.availableDevices[0];
    if (fallback) {
      this._ui.updateDeviceUI(fallback.label, this._isHeadphoneMic(fallback.label));
      this._ui.syncDeviceDropdown(fallback.deviceId);
    } else {
      this._ui.updateDeviceUI('Default microphone', false);
    }
  }

  private _isHeadphoneMic(label: string): boolean {
    if (!label) return false;
    const l = label.toLowerCase();
    if (l.includes('bluetooth') || l.includes('airpod')) return false;
    return l.includes('headphone') || l.includes('headset') || l.includes('earphone');
  }
}
