// src/scripts/daf/UIController.ts
// Single responsibility: all DOM reads/writes for the DAF app.
// No audio logic, no timers, no business state.

type StatusType = 'success' | 'error' | 'loading' | 'warning' | 'info';

const STATUS_CLASS_MAP: Record<string, string> = {
  success: 'status-success',
  error:   'status-error',
  loading: 'status-loading',
  warning: 'status-warning',
  info:    'status-info',
};

export class UIController {
  updateStatus(message: string, type: StatusType = 'info'): void {
    const el = document.getElementById('statusMessage');
    if (!el) return;
    el.textContent = message;
    el.classList.remove(
      'status-success', 'status-error', 'status-warning',
      'status-info', 'status-default', 'status-loading',
    );
    el.classList.add(STATUS_CLASS_MAP[type] ?? 'status-default');
  }

  updateDisplay(elementId: string, value: string): void {
    const el = document.getElementById(elementId);
    if (el) el.textContent = value;
  }

  updateControls(isActive: boolean): void {
    const btn = document.getElementById('dafButton');
    if (!btn) return;
    btn.textContent = isActive ? 'Stop DAF' : 'Start DAF';
    btn.setAttribute('aria-pressed', String(isActive));
  }

  /**
   * Update the microphone icon (#deviceIcon) to reflect headphone vs regular mic.
   * The device name is no longer shown in a separate element — the dropdown
   * shows the selected device name instead.
   */
  updateDeviceUI(deviceName: string, isHeadphoneMic: boolean): void {
    const iconEl = document.getElementById('deviceIcon');
    if (iconEl) iconEl.textContent = isHeadphoneMic ? '🎧' : '🎙️';
    // deviceName unused directly — dropdown shows it via populateDeviceDropdown
    void deviceName;
  }

  /**
   * Rebuild the #deviceSelect dropdown from the full device list.
   * Called after enumerate() resolves (has labels) and after devicechange events.
   * Falls back to "Microphone N" for unlabelled entries (pre-permission).
   */
  populateDeviceDropdown(devices: MediaDeviceInfo[], selectedId: string | null): void {
    const sel = document.getElementById('deviceSelect') as HTMLSelectElement | null;
    if (!sel) return;

    sel.innerHTML = '';

    if (devices.length === 0) {
      const opt = document.createElement('option');
      opt.value    = '';
      opt.textContent = 'No microphones found';
      sel.appendChild(opt);
      sel.disabled = true;
      return;
    }

    sel.disabled = false;
    devices.forEach((d, i) => {
      const opt = document.createElement('option');
      opt.value = d.deviceId;
      opt.textContent = d.label || `Microphone ${i + 1}`;
      if (d.deviceId === selectedId) opt.selected = true;
      sel.appendChild(opt);
    });

    if (!sel.value && devices.length > 0) {
      sel.options[0]!.selected = true;
    }
  }

  /**
   * Show a disabled placeholder when microphone permission hasn't been
   * granted yet. The user needs to start DAF to trigger getUserMedia.
   */
  setDeviceDropdownPending(): void {
    const sel = document.getElementById('deviceSelect') as HTMLSelectElement | null;
    if (!sel) return;
    sel.innerHTML = '';
    const opt = document.createElement('option');
    opt.value       = '';
    opt.textContent = 'Start DAF to see available microphones';
    sel.appendChild(opt);
    sel.disabled = true;
  }

  /**
   * Set the dropdown's displayed value without rebuilding options.
   * If deviceId is not found in current options (e.g. device was unplugged),
   * falls back to the first available option rather than showing blank.
   */
  syncDeviceDropdown(deviceId: string | null): void {
    if (!deviceId) return;
    const sel = document.getElementById('deviceSelect') as HTMLSelectElement | null;
    if (!sel) return;
    sel.value = deviceId;
    // sel.value stays "" if deviceId isn't in options — fall back to first option
    if (!sel.value && sel.options.length > 0) {
      sel.options[0]!.selected = true;
    }
  }
}
