// src/scripts/daf/SessionTimer.ts
// Owns the #dafTimer element — start/stop/resume without resetting the display.

export class SessionTimer {
  private _intervalId: ReturnType<typeof setInterval> | null = null;
  private _startTime = 0;
  elapsedMs = 0;

  start(): void {
    const el = document.getElementById('dafTimer');
    if (!el) return;
    this._startTime = performance.now();
    this.elapsedMs = 0;
    el.textContent = '00:00';
    el.classList.add('timer-running');
    this._tick(el);
  }

  /**
   * Resume counting without resetting the visible display.
   * Useful when restarting audio for a device switch mid-session.
   */
  resume(): void {
    const el = document.getElementById('dafTimer');
    if (!el || this._intervalId) return;
    this._startTime = performance.now() - this.elapsedMs;
    el.classList.add('timer-running');
    this._tick(el);
  }

  /**
   * Pause the tick without resetting elapsedMs.
   * Used during a device switch — the display stays frozen but elapsed time
   * is preserved so resume() can continue from it.
   */
  pause(): void {
    if (this._intervalId) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }
    // elapsedMs intentionally kept intact
  }

  /** Full stop: clears the tick and resets elapsed time and display. */
  stop(): void {
    this.pause();
    this.elapsedMs = 0;
    const el = document.getElementById('dafTimer');
    if (el) {
      el.textContent = '00:00';
      el.classList.remove('timer-running');
    }
  }

  // ── private ─────────────────────────────────────────────────────────────────

  private _tick(el: HTMLElement): void {
    this._intervalId = setInterval(() => {
      this.elapsedMs = performance.now() - this._startTime;
      const s = Math.floor(this.elapsedMs / 1000);
      const mm = String(Math.floor(s / 60)).padStart(2, '0');
      const ss = String(s % 60).padStart(2, '0');
      el.textContent = `${mm}:${ss}`;
    }, 1000);
  }
}
