// src/scripts/daf/BenchmarkManager.ts
// Measures the auditory feedback loop latency and scheduling jitter.
//
// Two measurement sources:
//
// 1. STATIC  — AudioContext properties read directly:
//      baseLatency   : render-thread→hardware output pipeline delay
//      outputLatency : additional hardware output buffer
//      inputLatency  : from MediaStreamTrack.getSettings().latency (if available)
//      sampleRate    : context sample rate
//      Estimated buffer size = round(baseLatency × sampleRate)
//
// 2. DYNAMIC — a short AudioWorklet recording of scheduler timing:
//      Records currentTime at every render quantum for SAMPLE_COUNT quanta
//      (~580 ms at 44.1 kHz / ~533 ms at 48 kHz), then posts the interval
//      array back via port.postMessage.
//      Computed stats: min, max, mean, p95, stddev of inter-quantum intervals.
//      A perfect scheduler fires every 128/sampleRate ≈ 2.9 ms.
//      Jitter (stddev) < 0.5 ms is excellent; > 2 ms indicates scheduling
//      pressure that will cause audible timing variance in FAF.

export interface BenchmarkResult {
  // ── Static ──────────────────────────────────────────────────────────────────
  sampleRate:         number;
  baseLatencyMs:      number;
  outputLatencyMs:    number;
  inputLatencyMs:     number | null;
  fafLatencyMs:       number;
  totalFloorMs:       number;
  estimatedBufferSamples: number;

  // ── Dynamic (jitter) ────────────────────────────────────────────────────────
  quantumMs:          number;
  jitter: {
    minDriftMs:    number;  // most-early quantum (negative = arrived early)
    maxDriftMs:    number;  // most-late quantum
    meanDriftMs:   number;  // mean offset from expected (systematic bias)
    p95DriftMs:    number;  // 95th percentile of |drift|
    stddevMs:      number;  // spread of drift — the real jitter metric
    samples:       number;
  };
}

// ── Worklet source ────────────────────────────────────────────────────────────

const SAMPLE_COUNT = 200; // quanta to record (~580 ms @ 44.1 kHz)

const BENCHMARK_WORKLET_CODE = /* js */ `
(function () {
  'use strict';

  const SAMPLES = ${SAMPLE_COUNT};

  class BenchmarkProcessor extends AudioWorkletProcessor {
    constructor() {
      super();
      this._drifts = [];
      this._frame0 = -1;
      this._t0     = 0;
      this._done   = false;
    }

    process(_inputs, _outputs, _params) {
      if (this._done) return false;

      const wallMs = Date.now();

      if (this._frame0 === -1) {
        // Anchor: record the first quantum's frame count and wall time.
        // All subsequent drift measurements are relative to this pair.
        this._frame0 = currentFrame;
        this._t0     = wallMs;
        return true;
      }

      // Expected wall time = anchor + exact sample-accurate elapsed time.
      // currentFrame is integer samples — no resolution loss here.
      // Date.now() has 1ms resolution, but the DRIFT (deviation from expected)
      // still exposes scheduling pressure: a quantum consistently 5ms late
      // will show as drift ≈ +5ms regardless of Date.now() coarsening.
      const expectedMs = this._t0 + ((currentFrame - this._frame0) / sampleRate) * 1000;
      this._drifts.push(wallMs - expectedMs);

      if (this._drifts.length >= SAMPLES) {
        this._done = true;
        this.port.postMessage({ drifts: this._drifts });
        return false;
      }

      return true;
    }
  }

  registerProcessor('benchmark-processor', BenchmarkProcessor);
})();
`;

// ── Loader ───────────────────────────────────────────────────────────────────

async function _loadBenchmarkWorklet(ctx: AudioContext): Promise<void> {
  // No caching — always create a fresh blob so code changes take effect.
  // The blob is small (~600 bytes) and addModule() is only called once per
  // AudioContext instance (AudioGraph.close() sets _workletReady=false).
  const blob = new Blob([BENCHMARK_WORKLET_CODE], { type: 'application/javascript' });
  const url  = URL.createObjectURL(blob);
  try {
    await ctx.audioWorklet.addModule(url);
  } finally {
    URL.revokeObjectURL(url);
  }
}

// ── Stats helpers ─────────────────────────────────────────────────────────────

function _mean(arr: number[]): number {
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function _stddev(arr: number[], mean: number): number {
  const variance = arr.reduce((a, b) => a + (b - mean) ** 2, 0) / arr.length;
  return Math.sqrt(variance);
}

function _p95(arr: number[]): number {
  const sorted = [...arr].sort((a, b) => a - b);
  return sorted[Math.floor(sorted.length * 0.95)] ?? sorted[sorted.length - 1] ?? 0;
}

// ── Main export ───────────────────────────────────────────────────────────────

/**
 * Run a full benchmark on the given AudioContext.
 * The context must be in 'running' state.
 * Takes ~600 ms to complete (200 render quanta).
 */
export async function runBenchmark(
  ctx: AudioContext,
  stream: MediaStream | null,
  fafLatencyMs: number,
): Promise<BenchmarkResult> {
  if (ctx.state !== 'running') {
    throw new Error(`AudioContext must be running (current state: ${ctx.state})`);
  }

  // ── Static measurements ───────────────────────────────────────────────────
  const baseLatencyMs   = (ctx.baseLatency   ?? 0) * 1000;
  const outputLatencyMs = (ctx.outputLatency ?? 0) * 1000;

  let inputLatencyMs: number | null = null;
  try {
    const settings = stream?.getAudioTracks?.()?.[0]?.getSettings?.();
    if (settings?.latency) inputLatencyMs = settings.latency * 1000;
  } catch { /* browser differences */ }

  const totalFloorMs = baseLatencyMs + outputLatencyMs + (inputLatencyMs ?? 0);
  const estimatedBufferSamples = Math.round(ctx.baseLatency * ctx.sampleRate);
  const quantumMs = (128 / ctx.sampleRate) * 1000;

  // ── Dynamic measurement ───────────────────────────────────────────────────
  await _loadBenchmarkWorklet(ctx);

  const drifts = await new Promise<number[]>((resolve, reject) => {
    let node: AudioWorkletNode | null = null;

    const timeout = setTimeout(() => {
      try { node?.disconnect(); } catch { /* ignore */ }
      reject(new Error('Benchmark timed out'));
    }, 5000);

    try {
      node = new AudioWorkletNode(ctx, 'benchmark-processor', {
        numberOfInputs:  0,
        numberOfOutputs: 1,
        outputChannelCount: [1],
      });

      node.port.onmessage = (e: MessageEvent<{ drifts: number[] }>) => {
        clearTimeout(timeout);
        try { node!.disconnect(); } catch { /* ignore */ }
        resolve(e.data.drifts);
      };

      node.onprocessorerror = (e) => {
        clearTimeout(timeout);
        reject(new Error(`Benchmark worklet error: ${e}`));
      };

      node.connect(ctx.destination);
    } catch (err) {
      clearTimeout(timeout);
      reject(err);
    }
  });

  if (drifts.length < 10) {
    throw new Error(`Too few samples collected (${drifts.length})`);
  }

  // Drift = (actual wall time) − (expected wall time based on currentFrame).
  // Positive = quantum arrived late; negative = arrived early.
  // stddev of drift is the canonical jitter metric.
  const absDrifts = drifts.map(Math.abs);
  const meanDriftMs   = _mean(drifts);
  const stddevMs      = _stddev(drifts, meanDriftMs);
  const p95DriftMs    = _p95(absDrifts);   // p95 of |drift| — worst-case lateness
  const minDriftMs    = Math.min(...drifts);
  const maxDriftMs    = Math.max(...drifts);

  return {
    sampleRate:             ctx.sampleRate,
    baseLatencyMs:          Math.round(baseLatencyMs   * 10) / 10,
    outputLatencyMs:        Math.round(outputLatencyMs * 10) / 10,
    inputLatencyMs:         inputLatencyMs !== null ? Math.round(inputLatencyMs * 10) / 10 : null,
    fafLatencyMs:           Math.round(fafLatencyMs    * 10) / 10,
    totalFloorMs:           Math.round(totalFloorMs    * 10) / 10,
    estimatedBufferSamples,
    quantumMs:              Math.round(quantumMs       * 100) / 100,
    jitter: {
      minDriftMs:  Math.round(minDriftMs  * 10) / 10,
      maxDriftMs:  Math.round(maxDriftMs  * 10) / 10,
      meanDriftMs: Math.round(meanDriftMs * 10) / 10,
      p95DriftMs:  Math.round(p95DriftMs  * 10) / 10,
      stddevMs:    Math.round(stddevMs    * 10) / 10,
      samples:     drifts.length,
    },
  };
}